// Helper function to get champion by ID
export function getChampion(id) {
    return CHAMPION_DATA[id];
}
// Helper function to get all champion IDs
export function getAllChampionIds() {
    return Object.keys(CHAMPION_DATA);
}
// Helper function to get champion stats at level
export function getChampionStatsAtLevel(championId, level) {
    const champion = CHAMPION_DATA[championId];
    if (!champion)
        return undefined;
    return {
        health: champion.stats.health + (level - 1) * champion.stats.healthPerLevel,
        healthPerLevel: champion.stats.healthPerLevel,
        mana: champion.stats.mana + (level - 1) * champion.stats.manaPerLevel,
        manaPerLevel: champion.stats.manaPerLevel,
        armor: champion.stats.armor + (level - 1) * champion.stats.armorPerLevel,
        armorPerLevel: champion.stats.armorPerLevel,
        magicResist: champion.stats.magicResist + (level - 1) * champion.stats.magicResistPerLevel,
        magicResistPerLevel: champion.stats.magicResistPerLevel,
        moveSpeed: champion.stats.moveSpeed,
        attackRange: champion.stats.attackRange,
        attackDamage: champion.stats.attackDamage + (level - 1) * champion.stats.attackDamagePerLevel,
        attackDamagePerLevel: champion.stats.attackDamagePerLevel,
        attackSpeed: champion.stats.attackSpeed * (1 + (level - 1) * champion.stats.attackSpeedPerLevel / 100),
        attackSpeedPerLevel: champion.stats.attackSpeedPerLevel,
        critChance: champion.stats.critChance,
        critDamage: champion.stats.critDamage,
        spellBlock: champion.stats.spellBlock,
    };
}
// Get ability by champion and key
export function getAbility(championId, key) {
    const champion = CHAMPION_DATA[championId];
    if (!champion)
        return undefined;
    return champion.abilities.find(a => a.key === key);
}
